const today = new Date();
const dateStart = new Date(today);
const dateEnd = new Date(today);
dateEnd.setDate(dateEnd.getDate() + 14);

const entries = $input.all();
const filtered = [];

for (const entry of entries) {
  const props = entry.json.properties;
  const dateProp = props?.Date?.date;

  if (!dateProp || !dateProp.start) continue;

  const entryDate = new Date(dateProp.start);
  const mappedDate = new Date(today.getFullYear(), entryDate.getMonth(), entryDate.getDate());

  if (mappedDate >= dateStart && mappedDate <= dateEnd) {
    filtered.push({
      json: {
        pageId: entry.json.id,
        name: props?.Name?.title?.map(t => t.plain_text).join('') || '',
        date: mappedDate.toISOString().split('T')[0],
        types: props?.['Email Type']?.multi_select?.map(s => s.name) || []
      }
    });
  }
}

return filtered;

const items = $input.all();
const topicInfo = items.find(i => i.json.pageId)?.json;

if (!topicInfo) {
  return [{ json: { error: 'No topic info found' } }];
}

const blocks = items.filter(i => i.json.type && !i.json.pageId);
const contentParts = [];

for (const block of blocks) {
  const type = block.json.type;
  let text = '';

  if (type === 'paragraph') {
    text = block.json.paragraph?.rich_text?.map(t => t.plain_text).join('');
  } else if (type === 'bulleted_list_item') {
    text = '• ' + block.json.bulleted_list_item?.rich_text?.map(t => t.plain_text).join('');
  } else if (type === 'numbered_list_item') {
    text = block.json.numbered_list_item?.rich_text?.map(t => t.plain_text).join('');
  } else if (type === 'heading_1') {
    text = '# ' + block.json.heading_1?.rich_text?.map(t => t.plain_text).join('');
  } else if (type === 'heading_2') {
    text = '## ' + block.json.heading_2?.rich_text?.map(t => t.plain_text).join('');
  } else if (type === 'heading_3') {
    text = '### ' + block.json.heading_3?.rich_text?.map(t => t.plain_text).join('');
  } else if (type === 'quote') {
    text = '> ' + block.json.quote?.rich_text?.map(t => t.plain_text).join('');
  } else if (type === 'callout') {
    text = '💡 ' + block.json.callout?.rich_text?.map(t => t.plain_text).join('');
  } else if (type === 'image') {
    const caption = block.json.image?.caption?.map(t => t.plain_text).join('') || 'Image';
    text = `[BILD: ${caption}]`;
  }

  if (text.trim()) {
    contentParts.push(text);
  }
}

return [{
  json: {
    ...topicInfo,
    notionContent: contentParts.join('\n\n'),
    contentParts: contentParts
  }
}];

const records = $input.all();

return records.map(r => ({
  json: {
    id: r.json.id,
    firmenname: r.json.fields?.Firmenname || '',
    klaviyoKey: r.json.fields?.['Klaviyo API Key'] || '',
    website: r.json.fields?.Website || '',
    branche: r.json.fields?.Branche || '',
    tonalitaet: r.json.fields?.Tonalität || '',
    emailFrom: r.json.fields?.['E-Mail Rechnungen'] || 'hello@adsdrop.de'
  }
})).filter(c => c.json.klaviyoKey);

const items = $input.all();

const topics = items.filter(i => i.json.notionContent).map(i => i.json);
const clients = items.filter(i => i.json.klaviyoKey && !i.json.notionContent).map(i => i.json);

if (topics.length === 0) throw new Error('No topics with content found');
if (clients.length === 0) throw new Error('No clients found');

const combos = [];
for (const client of clients) {
  for (const topic of topics) {
    combos.push({
      json: {
        comboId: `${client.id}_${topic.pageId}`,
        topic: topic,
        client: client
      }
    });
  }
}

return combos;

const combo = $input.first().json;
const client = combo.client;

if (!client.website) {
  return [{
    json: {
      ...combo,
      websiteAnalysis: null,
      websiteError: 'No website URL'
    }
  }];
}

try {
  const resp = await $httpRequest({
    method: 'GET',
    url: client.website,
    timeout: 15000,
    options: { redirect: 'follow' }
  });

  const html = (typeof resp === 'string' ? resp : resp.body || '').toLowerCase();

  const products = [];
  const keywords = {
    'Mode': ['kleidung', 'fashion', 'bekleidung', 'outfit', 'style'],
    'Beauty': ['kosmetik', 'beauty', 'pflege', 'makeup', 'hautpflege'],
    'Home': ['möbel', 'home', 'wohnen', 'einrichtung', 'deko', 'interior'],
    'Tech': ['technik', 'gadgets', 'elektronik', 'smart', 'digital'],
    'Food': ['food', 'essen', 'kulinarik', 'gourmet', 'kaffee', 'snacks'],
    'Sport': ['sport', 'fitness', 'training', 'workout', 'active'],
    'Jewelry': ['schmuck', 'jewelry', 'uhren', 'accessoires']
  };

  for (const [cat, words] of Object.entries(keywords)) {
    if (words.some(w => html.includes(w))) products.push(cat);
  }

  const luxury = ['luxus', 'premium', 'exklusiv', 'hochwertig', 'edel', 'elegant'].filter(w => html.includes(w)).length;
  const casual = ['mega', 'super', 'cool', 'easy', 'entspannt', 'lässig', 'geil'].filter(w => html.includes(w)).length;

  let tone = 'standard';
  if (luxury > 2) tone = 'luxury';
  else if (casual > 2) tone = 'casual';

  const uspWords = ['nachhaltig', 'bio', 'vegan', 'handmade', 'regional', 'fair', 'öko', 'sustainable'];
  const usp = uspWords.find(w => html.includes(w)) || 'Qualität und Service';

  const guarantee = html.includes('versand') && html.includes('kostenlos') 
    ? 'Kostenloser Versand' 
    : html.includes('rückgabe') 
      ? '30 Tage Rückgabe' 
      : 'Kundenzufriedenheit garantiert';

  return [{
    json: {
      ...combo,
      websiteAnalysis: {
        products: products.length > 0 ? products : ['Produkte'],
        mainProduct: products[0] || 'Produkte',
        tone: tone,
        usp: usp,
        guarantee: guarantee,
        hasShippingInfo: html.includes('versand'),
        hasReturnsInfo: html.includes('rückgabe') || html.includes('retoure')
      }
    }
  }];
} catch (error) {
  return [{
    json: {
      ...combo,
      websiteAnalysis: {
        products: ['Produkte'],
        mainProduct: 'Produkte',
        tone: 'standard',
        usp: 'Qualität und Service',
        guarantee: 'Kundenzufriedenheit'
      },
      websiteError: error.message
    }
  }];
}
